import { execSync } from "child_process";
import os from "os";

/**
 * Opens a file or URL using the default system application
 * Works on macOS, Windows, and Linux
 * @param {string} resource - File path or URL
 */
export function openResource(resource) {
  const platform = os.platform();

  try {
    if (platform === "darwin") {
      execSync(`open "${resource}"`);
    } else if (platform === "win32") {
      execSync(`start "" "${resource}"`, { shell: "cmd.exe" });
    } else if (platform === "linux") {
      execSync(`xdg-open "${resource}"`);
    } else {
      console.error(`❌ Unsupported platform: ${platform}`);
    }
  } catch (err) {
    console.error(`⚠️  Failed to open resource: ${err.message}`);
  }
}
